  ('dietitian-moex-03142', 'dietitian', 'dietitian-moex-103-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '酗酒超過20年之成年男子，現因吐血、胡言亂語、意識不清、失去方向感、有攻擊傾向而就診。經檢查發 現體溫為攝氏38.6度、白血球計數為23,000 cells/mL、血紅素10.2 g/dL、生化檢驗值為：鈉130 mEq/L、 鉀5.1 mEq/L、血中尿素氮30 mg/dL、肌酸酐2.3 mg/dL、白蛋白2.2 g/dL、膽紅素總量3.9 mg/dL、天門 冬胺酸轉胺酶260 U/L、丙胺酸轉胺酶96 U/L、鹼性磷酸酶203 U/L。在此階段對該患者營養治療，下列 敘述何者最合宜？', '["蛋白質每公斤體重0.6公克，來源以動物性為主", "蛋白質每公斤體重0.6公克，來源以植物性為主", "蛋白質每公斤體重1.2公克，來源以動物性為主", "蛋白質每公斤體重1.2公克，來源以植物性為主"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:00+00:00", "source_pdf_sha1": "d07ea8910d7c", "answer_pdf_sha1": "68b729a28fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "106", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
